package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Constructor;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  static class TestRecord {
    public int x;
  }

  static class NonRecord {
  }

  @Test
  void isRecord_returnsTrue_whenRecordHelperReturnsTrue() throws Exception {
    // Use reflection to get the private static final RECORD_HELPER field
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class)) {
      Object mockRecordHelper = mock(recordHelperField.getType());
      // Replace the RECORD_HELPER field value via reflection
      recordHelperField.set(null, mockRecordHelper);

      // Use reflection to stub the isRecord method on the mockRecordHelper
      when(recordHelperField.getType().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class))
          .thenReturn(true);

      // Since direct when().thenReturn() with reflection invoke is complicated,
      // stub the method using Mockito's doReturn:
      doReturn(true).when(mockRecordHelper).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class);

      // Instead, stub via Mockito on the mock object directly:
      when(recordHelperField.getType().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class))
          .thenReturn(true);

      // To avoid reflection issues, cast mockRecordHelper to Object and use Mockito's when on the method call:
      // But since we cannot cast to RecordHelper (not visible), we use reflection to stub:
      // So, better to stub via Mockito's Answer:
      // But this is complicated, so instead we do:
      // Use Mockito's doReturn to stub the method on the mockRecordHelper object:
      // But since mockRecordHelper is a mock, we can stub its method via reflection proxy:

      // Actually, the above is complicated and unnecessary; just stub the method on the mockRecordHelper:
      when(recordHelperField.getType().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class))
          .thenReturn(true);

      boolean result = ReflectionHelper.isRecord(TestRecord.class);

      assertTrue(result);

      // Verify that isRecord was called on mockRecordHelper with TestRecord.class
      verify(mockRecordHelper).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, TestRecord.class);
    }
  }

  @Test
  void isRecord_returnsFalse_whenRecordHelperReturnsFalse() throws Exception {
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class)) {
      Object mockRecordHelper = mock(recordHelperField.getType());
      recordHelperField.set(null, mockRecordHelper);

      when(recordHelperField.getType().getMethod("isRecord", Class.class).invoke(mockRecordHelper, NonRecord.class))
          .thenReturn(false);

      boolean result = ReflectionHelper.isRecord(NonRecord.class);

      assertFalse(result);

      verify(mockRecordHelper).getClass().getMethod("isRecord", Class.class).invoke(mockRecordHelper, NonRecord.class);
    }
  }
}
